const html =
  $node["22. Humanize_Content"].json.content?.[0]?.text
  || '';

const keyword = $node["2. Set_Clean_Variables3"].json.PrimaryKeyword || '';
const pillarUrl = $node["13. Get_Pillar_Data"].json.Pillar_URL || '';
const linkListText = $node["15. Format_Link_List"].json.link_list_text || '';

const stripTags = (s) => s.replace(/<[^>]+>/g, ' ');
const words = stripTags(html).trim().split(/\s+/).filter(Boolean);
const wordCount = words.length;

const hasH2 = /<h2[\s>]/i.test(html);
const hasH3 = /<h3[\s>]/i.test(html);

const hasPillarUrl = Boolean(pillarUrl);
const hasPillarLink = hasPillarUrl ? html.includes(pillarUrl) : false;

const requiresInternalLinks = !/No existing posts found/i.test(linkListText);
let hasInternalLink = true;
if (requiresInternalLinks) {
  const hrefs = [...html.matchAll(/href=["']([^"']+)["']/gi)].map(m => m[1]);
  hasInternalLink = hrefs.some(u => u && u !== pillarUrl);
}

const minWords = 900;
const hasMinWords = wordCount >= minWords;

const banned = ["ai detector", "undetectable by ai", "perplexity", "burstiness"];
const containsBanned = banned.some(p => html.toLowerCase().includes(p));

const fakeExperiencePatterns = [/\bI tested\b/i, /\bin my experience\b/i, /\bour data shows\b/i];
const containsFakeExperience = fakeExperiencePatterns.some(r => r.test(html));

const failures = [];
if (!keyword) failures.push("Missing PrimaryKeyword.");
if (!hasPillarUrl) failures.push("Missing Pillar_URL (PillarParent did not resolve).");
if (!hasPillarLink) failures.push("Draft missing required pillar link.");
if (!hasH2) failures.push("No <h2> tags found.");
if (!hasH3) failures.push("No <h3> tags found.");
if (!hasMinWords) failures.push(`Too short: ${wordCount} words (min ${minWords}).`);
if (!hasInternalLink) failures.push("No internal links found (LinkIndex not empty).");
if (containsBanned) failures.push("Contains banned detector/meta-writing language.");
if (containsFakeExperience) failures.push("Contains 1st-person testing/experience claims.");

return [{
  json: {
    qa: { pass: failures.length === 0, failures, wordCount, pillarUrl },
    html
  }
}];

