const html = $('P11. HumanizePillarContent').item.json.content?.[0]?.text;
const Pillar_Topic = $('P2. SetCleanPillarVars').item.json.Pillar_Topic;
const linkArray = $('P8. FormatClusterLinksForPillar').item.json.linkArray || [];

// Strip HTML tags for word count
const stripTags = (s) => s.replace(/<[^>]*>/g, '');
const words = stripTags(html).trim().split(/\s+/).filter(Boolean);
const wordCount = words.length;

// Structure checks
const hasH2 = /<h2/i.test(html);
const hasH3 = /<h3/i.test(html);
const hasTopic = html.toLowerCase().includes(Pillar_Topic.toLowerCase());

// Internal link check
const requiresClusterLinks = linkArray.length > 0;
let hasClusterLinks = true;
if (requiresClusterLinks) {
  const hrefs = [...html.matchAll(/href="([^"]+)"/gi)].map(m => m[1]);
  hasClusterLinks = linkArray.some(link => hrefs.includes(link.url));
}

// Min word count for pillar
const minWords = 2000;
const hasMinWords = wordCount >= minWords;

// Banned phrases
const banned = ["ai detector", "undetectable by ai", "perplexity", "burstiness"];
const containsBanned = banned.some(p => html.toLowerCase().includes(p));

// Fake experience patterns
const fakeExperiencePatterns = [/tested\s+this/i, /my\s+experience/i, /data\s+shows/i];
const containsFakeExperience = fakeExperiencePatterns.some(r => r.test(html));

// Collect failures
const failures = [];
if (!Pillar_Topic) failures.push("Missing Pillar_Topic.");
if (!hasH2) failures.push("No h2 tags found.");
if (!hasH3) failures.push("No h3 tags found.");
if (!hasTopic) failures.push("Content doesn't mention pillar topic.");
if (!hasMinWords) failures.push(`Too short: ${wordCount} words (min ${minWords}).`);
if (!hasClusterLinks && requiresClusterLinks) failures.push("No internal cluster links found.");
if (containsBanned) failures.push("Contains banned AI detector language.");
if (containsFakeExperience) failures.push("Contains 1st-person testing/experience claims.");

return [{
  json: {
    qa: {
      pass: failures.length === 0,
      failures,
      wordCount,
      hasClusterLinks
    },
    html
  }
}];

